arguments.file_text:
namespace UniversityCourseCatalog.Models;

public record Department
{
    public required string Id { get; init; }
    public required string Name { get; init; }
    public required string Description { get; init; }
}

public record Instructor
{
    public required string Name { get; init; }
    public required string Title { get; init; }
    public required string Bio { get; init; }
    public required string Email { get; init; }
}

public record Course
{
    public required string Id { get; init; }
    public required string Title { get; init; }
    public required string DepartmentId { get; init; }
    public required string Description { get; init; }
    public required int Credits { get; init; }
    public required string Schedule { get; init; }
    public required string Location { get; init; }
    public required Instructor Instructor { get; init; }
    public bool IsFeatured { get; init; }
}

public class EnrollmentRequest
{
    public string StudentName { get; set; } = "";
    public string StudentId { get; set; } = "";
    public string CourseId { get; set; } = "";
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments =
        [
            new Department { Id = "cs", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
            new Department { Id = "math", Name = "Mathematics", Description = "Pure and applied mathematics, statistics, and data analysis." },
            new Department { Id = "eng", Name = "English", Description = "Literature, composition, creative writing, and linguistics." },
            new Department { Id = "phys", Name = "Physics", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new Department { Id = "hist", Name = "History", Description = "Exploration of human civilizations, events, and cultural change." },
            new Department { Id = "bio", Name = "Biology", Description = "Study of living organisms, genetics, and ecosystems." },
        ];

        _courses =
        [
            // Computer Science
            new Course
            {
                Id = "CS101", Title = "Introduction to Programming", DepartmentId = "cs",
                Description = "Learn the fundamentals of programming using C#. Topics include variables, control flow, object-oriented design, and basic data structures. No prior experience required.",
                Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", Location = "Science Hall 201",
                Instructor = new Instructor { Name = "Dr. Alice Chen", Title = "Associate Professor", Bio = "Dr. Chen specializes in programming languages and software engineering education. She has published extensively on introductory CS pedagogy.", Email = "achen@university.edu" },
                IsFeatured = true,
            },
            new Course
            {
                Id = "CS301", Title = "Data Structures and Algorithms", DepartmentId = "cs",
                Description = "Advanced study of data structures (trees, graphs, hash tables) and algorithm analysis. Covers sorting, searching, dynamic programming, and computational complexity.",
                Credits = 4, Schedule = "Tue/Thu 10:30–11:45 AM", Location = "Science Hall 305",
                Instructor = new Instructor { Name = "Dr. Robert Kim", Title = "Professor", Bio = "Dr. Kim's research focuses on algorithm optimization and parallel computing. He has 20+ years of teaching experience.", Email = "rkim@university.edu" },
            },
            new Course
            {
                Id = "CS405", Title = "Machine Learning", DepartmentId = "cs",
                Description = "Introduction to machine learning concepts including supervised and unsupervised learning, neural networks, and model evaluation. Hands-on projects with real-world datasets.",
                Credits = 3, Schedule = "Mon/Wed 2:00–3:15 PM", Location = "Tech Building 110",
                Instructor = new Instructor { Name = "Dr. Priya Sharma", Title = "Assistant Professor", Bio = "Dr. Sharma joined the faculty after working at a major AI research lab. Her work spans natural language processing and computer vision.", Email = "psharma@university.edu" },
                IsFeatured = true,
            },

            // Mathematics
            new Course
            {
                Id = "MATH101", Title = "Calculus I", DepartmentId = "math",
                Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics, engineering, and economics.",
                Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", Location = "Math Building 102",
                Instructor = new Instructor { Name = "Dr. James Lee", Title = "Professor", Bio = "Dr. Lee is an award-winning educator with research interests in differential equations and mathematical modeling.", Email = "jlee@university.edu" },
            },
            new Course
            {
                Id = "MATH250", Title = "Linear Algebra", DepartmentId = "math",
                Description = "Vector spaces, matrices, determinants, eigenvalues, and linear transformations. Essential for advanced study in science and engineering.",
                Credits = 3, Schedule = "Tue/Thu 1:00–2:15 PM", Location = "Math Building 205",
                Instructor = new Instructor { Name = "Dr. Maria Gonzalez", Title = "Associate Professor", Bio = "Dr. Gonzalez researches abstract algebra and its applications in cryptography. She is a recipient of the university teaching excellence award.", Email = "mgonzalez@university.edu" },
                IsFeatured = true,
            },

            // English
            new Course
            {
                Id = "ENG101", Title = "College Composition", DepartmentId = "eng",
                Description = "Develop critical thinking and academic writing skills through essay composition, peer review, and revision. Emphasis on argumentation and research-based writing.",
                Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", Location = "Humanities Hall 115",
                Instructor = new Instructor { Name = "Prof. Sarah Mitchell", Title = "Senior Lecturer", Bio = "Prof. Mitchell has taught composition for 15 years and is the author of two rhetoric textbooks.", Email = "smitchell@university.edu" },
            },
            new Course
            {
                Id = "ENG320", Title = "American Literature", DepartmentId = "eng",
                Description = "Survey of American literary traditions from the colonial period to the present. Readings include works by Hawthorne, Whitman, Morrison, and contemporary authors.",
                Credits = 3, Schedule = "Tue/Thu 3:00–4:15 PM", Location = "Humanities Hall 210",
                Instructor = new Instructor { Name = "Dr. David Park", Title = "Associate Professor", Bio = "Dr. Park specializes in 20th-century American fiction and has published on the intersection of literature and social justice.", Email = "dpark@university.edu" },
            },

            // Physics
            new Course
            {
                Id = "PHYS201", Title = "General Physics I", DepartmentId = "phys",
                Description = "Mechanics, thermodynamics, and waves. Calculus-based approach with weekly lab sessions. Covers Newton's laws, energy conservation, and fluid dynamics.",
                Credits = 4, Schedule = "Mon/Wed/Fri 1:00–1:50 PM + Thu Lab 2:00–4:50 PM", Location = "Physics Lab 101",
                Instructor = new Instructor { Name = "Dr. Elena Vasquez", Title = "Professor", Bio = "Dr. Vasquez is a condensed matter physicist whose passion for teaching has earned her multiple departmental awards.", Email = "evasquez@university.edu" },
                IsFeatured = true,
            },

            // History
            new Course
            {
                Id = "HIST101", Title = "World History to 1500", DepartmentId = "hist",
                Description = "Survey of world civilizations from prehistory to 1500 CE. Examines political, social, and cultural developments across Africa, Asia, Europe, and the Americas.",
                Credits = 3, Schedule = "Tue/Thu 9:00–10:15 AM", Location = "Liberal Arts 304",
