@page "/catalog"
@using UniversityCourseCatalog.Services
@rendermode InteractiveServer
@inject CatalogService Catalog

<PageTitle>Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search courses, instructors…"
               @bind="SearchTerm" @bind:event="oninput" />
    </div>
    <div class="col-md-4">
        <select class="form-select" @bind="SelectedDepartment">
            <option value="">All Departments</option>
            @foreach (var dept in Catalog.GetDepartments())
            {
                <option value="@dept.Id">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button class="btn btn-outline-secondary w-100" @onclick="ClearFilters">Clear</button>
    </div>
</div>

@{
    var results = Catalog.SearchCourses(SearchTerm, SelectedDepartment);
}

<p class="text-muted">@results.Count course(s) found</p>

<div class="list-group">
    @foreach (var course in results)
    {
        var dept = Catalog.GetDepartment(course.DepartmentId);
        <a href="course/@course.Id" class="list-group-item list-group-item-action">
            <div class="d-flex justify-content-between align-items-start">
                <div>
                    <h5 class="mb-1">@course.Id — @course.Title</h5>
                    <p class="mb-1 text-muted">@dept?.Name · @course.Credits credits · @course.Instructor.Name</p>
                    <small>@course.Schedule</small>
                </div>
                <span class="badge bg-primary rounded-pill">@course.Credits cr</span>
            </div>
        </a>
    }
</div>

@code {
    [SupplyParameterFromQuery(Name = "department")]
    public string? SelectedDepartment { get; set; }

    private string? SearchTerm { get; set; }

    private void ClearFilters()
    {
        SearchTerm = null;
        SelectedDepartment = "";
    }
}

@page "/course/{CourseId}"
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>@(course?.Title ?? "Course Not Found")</PageTitle>

@if (course is null)
{
    <h1>Course Not Found</h1>
    <p>The course "<strong>@CourseId</strong>" does not exist in the catalog.</p>
    <a href="catalog" class="btn btn-primary">Back to Catalog</a>
}
else
{
    var dept = Catalog.GetDepartment(course.DepartmentId);

    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="catalog">Catalog</a></li>
            <li class="breadcrumb-item"><a href="catalog?department=@dept?.Id">@dept?.Name</a></li>
            <li class="breadcrumb-item active" aria-current="page">@course.Id</li>
        </ol>
    </nav>

    <h1>@course.Id — @course.Title</h1>

    <div class="row mt-4">
        <div class="col-md-8">
            <h4>Description</h4>
            <p>@course.Description</p>

            <h4 class="mt-4">Schedule &amp; Location</h4>
            <table class="table table-bordered w-auto">
                <tr><th>Schedule</th><td>@course.Schedule</td></tr>
                <tr><th>Location</th><td>@course.Location</td></tr>
                <tr><th>Credits</th><td>@course.Credits</td></tr>
            </table>
        </div>

        <div class="col-md-4">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">Instructor</h5>
                    <h6 class="card-subtitle mb-2 text-muted">@course.Instructor.Name</h6>
                    <p class="card-text"><em>@course.Instructor.Title</em></p>
                    <p class="card-text">@course.Instructor.Bio</p>
                    <a href="mailto:@course.Instructor.Email" class="card-link">@course.Instructor.Email</a>
                </div>
            </div>

            <a href="enroll?courseId=@course.Id" class="btn btn-success w-100 mt-3">Enroll in This Course</a>
        </div>
    </div>
}

@code {
    [Parameter]
    public string CourseId { get; set; } = "";

    private Models.Course? course;

    protected override void OnInitialized()
    {
        course = Catalog.GetCourse(CourseId);
    }
}

@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>

@if (Submitted)
{
    <div class="alert alert-success" role="alert">
        <h4 class="alert-heading">Request Submitted!</h4>
        <p>Thank you, <strong>@Model.StudentName</strong>. Your enrollment request for
            <strong>@SelectedCourse?.Id — @SelectedCourse?.Title</strong> has been received.</p>
        <hr />
        <p class="mb-0">You will receive a confirmation at your university email. <a href="">Return to Home</a></p>
    </div>
}
else
{
    <p class="text-muted">Complete the form below to request enrollment in a course.</p>

    <div class="row">
        <div class="col-md-8">
            <form method="post" @formname="enrollment" @onsubmit="HandleSubmit">
                <AntiforgeryToken />

                <div class="mb-3">
                    <label for="studentName" class="form-label">Full Name</label>
                    <input type="text" class="form-control" id="studentName" name="Model.StudentName"
                           value="@Model.StudentName" required />
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <input type="text" class="form-control" id="studentId" name="Model.StudentId"
                           value="@Model.StudentId" required placeholder="e.g. S12345678" />
                </div>

                <div class="mb-3">
                    <label for="courseId" class="form-label">Course</label>
                    <select class="form-select" id="courseId" name="Model.CourseId" required>
                        <option value="">— Select a course —</option>
                        @foreach (var course in Catalog.GetAllCourses())
                        {
                            var dept = Catalog.GetDepartment(course.DepartmentId);
                            if (course.Id == Model.CourseId)
                            {
                                <option value="@course.Id" selected>@course.Id — @course.Title (@dept?.Name)</option>
                            }
                            else
                            {
                                <option value="@course.Id">@course.Id — @course.Title (@dept?.Name)</option>
                            }
                        }
                    </select>
                </div>

                <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
                <a href="catalog" class="btn btn-link">Cancel</a>
            </form>
        </div>
    </div>
}

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest Model { get; set; } = new();

    [SupplyParameterFromQuery(Name = "courseId")]
    public string? PreselectedCourseId { get; set; }

    private bool Submitted { get; set; }
    private Course? SelectedCourse { get; set; }

    protected override void OnInitialized()
    {
        if (!string.IsNullOrEmpty(PreselectedCourseId) && string.IsNullOrEmpty(Model.CourseId))
        {
            Model.CourseId = PreselectedCourseId;
        }
    }

    private void HandleSubmit()
    {
        SelectedCourse = Catalog.GetCourse(Model.CourseId);
        Submitted = true;
    }
}

