 @page "/enroll"
 @using UniversityCourseCatalog.Models
 @using UniversityCourseCatalog.Services
 @inject CatalogService Catalog

 <PageTitle>Enrollment Request</PageTitle>

 <h1>Enrollment Request</h1>

 @if (Submitted)
 {
     <div class="alert alert-success" role="alert">
         <h4 class="alert-heading">Request Submitted!</h4>
         <p>Thank you, <strong>@Model.StudentName</strong>. Your enrollment request for
             <strong>@SelectedCourse?.Id — @SelectedCourse?.Title</strong> has been received.</p>
         <hr />
         <p class="mb-0">You will receive a confirmation at your university email. <a href="">Return to Home</a></p>
     </div>
 }
 else
 {
     <p class="text-muted">Complete the form below to request enrollment in a course.</p>

     <div class="row">
         <div class="col-md-8">
             <form method="post" @formname="enrollment" @onsubmit="HandleSubmit">
                 <AntiforgeryToken />

                 <div class="mb-3">
                     <label for="studentName" class="form-label">Full Name</label>
                     <input type="text" class="form-control" id="studentName" name="Model.StudentName"
                            value="@Model.StudentName" required />
                 </div>

                 <div class="mb-3">
                     <label for="studentId" class="form-label">Student ID</label>
                     <input type="text" class="form-control" id="studentId" name="Model.StudentId"
                            value="@Model.StudentId" required placeholder="e.g. S12345678" />
                 </div>

                 <div class="mb-3">
                     <label for="courseId" class="form-label">Course</label>
                     <select class="form-select" id="courseId" name="Model.CourseId" required>
                         <option value="">— Select a course —</option>
                         @foreach (var course in Catalog.GetAllCourses())
                         {
                             var dept = Catalog.GetDepartment(course.DepartmentId);
                             if (course.Id == Model.CourseId)
                             {
                                 <option value="@course.Id" selected>@course.Id — @course.Title (@dept?.Name)</option>
                             }
                             else
                             {
                                 <option value="@course.Id">@course.Id — @course.Title (@dept?.Name)</option>
                             }
                         }
                     </select>
                 </div>

                 <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
                 <a href="catalog" class="btn btn-link">Cancel</a>
             </form>
         </div>
     </div>
 }

